&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E4%B8%80%E7%AB%A0-%E8%AE%A1%E7%AE%97%E6%9C%BA%E4%B8%8E%E7%BD%91%E7%BB%9C%E5%AE%89%E5%85%A8%E6%A6%82%E5%BF%B5&#34;&gt;第一章 计算机与网络安全概念&lt;/a&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%9A%E4%B9%89&#34;&gt;定义&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#osi%E5%AE%89%E5%85%A8%E6%9E%B6%E6%9E%84&#34;&gt;OSI 安全架构&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%89%E5%85%A8%E6%94%BB%E5%87%BB&#34;&gt;安全攻击&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%89%E5%85%A8%E6%9C%8D%E5%8A%A1&#34;&gt;安全服务&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E5%AE%89%E5%85%A8%E6%9C%BA%E5%88%B6&#34;&gt;安全机制&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E4%B8%89%E7%AB%A0%E4%BC%A0%E7%BB%9F%E5%8A%A0%E5%AF%86%E6%8A%80%E6%9C%AF&#34;&gt;第三章传统加密技术&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%9B%9B%E7%AB%A0-%E5%88%86%E7%BB%84%E5%AF%86%E7%A0%81%E5%92%8C%E6%95%B0%E6%8D%AE%E5%8A%A0%E5%AF%86%E6%A0%87%E5%87%86&#34;&gt;第四章 分组密码和数据加密标准&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%85%AD%E7%AB%A0-%E9%AB%98%E7%BA%A7%E5%8A%A0%E5%AF%86%E6%A0%87%E5%87%86&#34;&gt;第六章 高级加密标准&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E4%B8%83%E7%AB%A0-%E5%88%86%E7%BB%84%E5%8A%A0%E5%AF%86%E7%9A%84%E5%B7%A5%E4%BD%9C%E6%A8%A1%E5%BC%8F&#34;&gt;第七章 分组加密的工作模式&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%85%AB%E7%AB%A0-%E4%BC%AA%E9%9A%8F%E6%9C%BA%E6%95%B0%E7%9A%84%E7%94%9F%E6%88%90%E5%92%8C%E6%B5%81%E5%AF%86%E7%A0%81&#34;&gt;第八章 伪随机数的生成和流密码&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E4%B9%9D%E7%AB%A0-%E5%85%AC%E9%92%A5%E5%AF%86%E7%A0%81%E5%AD%A6%E4%B8%8Ersa&#34;&gt;第九章 公钥密码学与 RSA&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E7%AB%A0-%E5%AF%86%E9%92%A5%E7%AE%A1%E7%90%86%E5%92%8C%E5%85%B6%E4%BB%96%E5%85%AC%E9%92%A5%E5%AF%86%E7%A0%81%E4%BD%93%E5%88%B6&#34;&gt;第十章 密钥管理和其他公钥密码体制&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E4%B8%80%E7%AB%A0-%E5%AF%86%E7%A0%81%E5%AD%A6hash%E5%87%BD%E6%95%B0&#34;&gt;第十一章 密码学 Hash 函数&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E4%BA%8C%E7%AB%A0-%E6%B6%88%E6%81%AF%E8%AE%A4%E8%AF%81%E7%A0%81&#34;&gt;第十二章 消息认证码&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E4%B8%89%E7%AB%A0-%E6%95%B0%E5%AD%97%E7%AD%BE%E5%90%8D&#34;&gt;第十三章 数字签名&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E5%9B%9B%E7%AB%A0-%E5%AF%86%E9%92%A5%E7%AE%A1%E7%90%86%E5%92%8C%E5%88%86%E5%8F%91&#34;&gt;第十四章 密钥管理和分发&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E7%AC%AC%E5%8D%81%E4%BA%94%E7%AB%A0-%E7%94%A8%E6%88%B7%E8%AE%A4%E8%AF%81&#34;&gt;第十五章 用户认证&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;!-- tocstop --&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;第一章-计算机与网络安全概念&#34;&gt; 第一章 计算机与网络安全概念&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;定义&#34;&gt; 定义&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;3 个阶段&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;传统安全（计算机出现之前）：物理管理方法（保险箱和锁）&lt;/li&gt;
&lt;li&gt;计算机安全：自动化工具、软件硬件、CIA（机密性、完整性、可用性）&lt;/li&gt;
&lt;li&gt;网络安全：通讯、网络设备（路由器、交换机、服务器、网关）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;网络空间安全（Cybersecurity）&lt;/li&gt;
&lt;li&gt;信息安全（Information Security）：（机密性、完整性、可用性）统称为计算机安全 CIA、真实性、可审计性&lt;/li&gt;
&lt;li&gt;网络安全（Network Security）：数据与服务在网络中的安全&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;机密性&lt;br&gt;
数据机密性：非授权的个体不可以访问秘密信息&lt;br&gt;
隐私：隐私数据、血型、生日、指纹不可以被可能泄露这些数据的第三方搜集&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;完整性&lt;br&gt;
数据完整性：信息只可以被授权的方式修改，如果信息被修改，可以发现（不可以恢复），MD5&lt;br&gt;
 系统完整性：系统只支持预期功能。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可用性：系统可以对合法用户的请求立刻产生响应&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;真实性：数据是真实的，可以被验证&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;可审计性：任何行为可以唯一的追踪到某个实体（日志）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/207.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C207.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;osi-安全架构&#34;&gt; OSI 安全架构&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;定义：提供一个系统的方法实现信息安全&lt;/li&gt;
&lt;li&gt;安全攻击：破坏 / 攻击系统安全性的行为&lt;/li&gt;
&lt;li&gt;安全机制：方法 / 算法用来检测、阻止、恢复在攻击中的系统&lt;/li&gt;
&lt;li&gt;安全服务：增强数据 / 信息安全性（阻止安全攻击）&lt;/li&gt;
&lt;li&gt;攻击三个步骤&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;选择攻击（泄密）&lt;/li&gt;
&lt;li&gt;选择服务（阻止攻击）&lt;br&gt;
方法：加密 AES、RSA&lt;/li&gt;
&lt;li&gt;选择机制（实现服务）&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;安全攻击&#34;&gt; 安全攻击&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;被动攻击：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;概念：跟踪、监视、偷听&lt;/li&gt;
&lt;li&gt;目的：得到数据&lt;/li&gt;
&lt;li&gt;检测：困难（不涉及对数据的更改）&lt;/li&gt;
&lt;li&gt;阻止：容易（加密数据）&lt;/li&gt;
&lt;li&gt;例子：信息泄露、流量分析（模式大小、源 IP、目的 IP、频率）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;主动攻击：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;概念：修改、伪造&lt;/li&gt;
&lt;li&gt;目的：干预、破坏&lt;/li&gt;
&lt;li&gt;检测：容易&lt;/li&gt;
&lt;li&gt;阻止：困难&lt;/li&gt;
&lt;li&gt;例子：伪装、重放、修改信息、拒绝服务攻击（Dos (攻击中耗尽服务器资源（计算、带宽、内存）)）&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;安全服务&#34;&gt; 安全服务&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;认证：验证身份&lt;/li&gt;
&lt;li&gt;访问控制：阻止非授权访问资源&lt;/li&gt;
&lt;li&gt;要求&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;数据保密性&lt;/li&gt;
&lt;li&gt;数据完整性&lt;/li&gt;
&lt;li&gt;不可否认性&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;A—&amp;gt;B&lt;br&gt;
A：不可以否认发送了信息&lt;br&gt;
 B：不可以否认接受了信息&lt;/li&gt;
&lt;li&gt;应用：股票交易服务&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/208.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C208.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/209.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C209.png&#34; alt&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;安全机制&#34;&gt; 安全机制&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;密码：机密性&lt;/li&gt;
&lt;li&gt;数字签名：相当于手写签名&lt;/li&gt;
&lt;li&gt;访问控制：资源访问控制机制&lt;/li&gt;
&lt;li&gt;数据完整性：SHA、MAC&lt;/li&gt;
&lt;li&gt;认证协议：保证实体身份&lt;/li&gt;
&lt;li&gt;流量填充：发送数据包过程中添加假数据&lt;/li&gt;
&lt;li&gt;路由控制：控制数据走安全路线&lt;/li&gt;
&lt;li&gt;公证：利用可信第三方保护数据&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/210.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C210.png&#34; alt&gt;&lt;br&gt;
9. 通讯安全&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;IPses—IP 安全&lt;/li&gt;
&lt;li&gt;SSL—HTTP 安全&lt;/li&gt;
&lt;li&gt;SIMIM— 电子邮件安全&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;10&#34;&gt;
&lt;li&gt;设备安全：防火墙、入侵检测、过滤器&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;第三章传统加密技术&#34;&gt; 第三章传统加密技术&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;学习假设情况：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;密钥：保密&lt;/li&gt;
&lt;li&gt;攻击者可知：加解密算法、密文&lt;/li&gt;
&lt;li&gt;攻击中目的：得到密钥，获取明文&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;密码学&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;盾：密码编码学（加密的科学方法）&lt;/li&gt;
&lt;li&gt;矛：密码分析学（破解未知密钥）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;密钥：保密，用于配置密码系统&lt;/li&gt;
&lt;li&gt;明文：原始信息&lt;/li&gt;
&lt;li&gt;密文：加密后的信息&lt;/li&gt;
&lt;li&gt;加密算法：明文 + key-&amp;gt; 密文&lt;/li&gt;
&lt;li&gt;解密算法：密文 + key-&amp;gt; 明文&lt;/li&gt;
&lt;li&gt;分类&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;加密类型（替换、置换、乘积）&lt;/li&gt;
&lt;li&gt;密钥个数&lt;br&gt;
（1）对称加密（单钥密码）：发送者和接受者共享一个密钥&lt;br&gt;
（2）非对称加密（双钥密码）：公钥、私钥&lt;/li&gt;
&lt;li&gt;明文处理方式&lt;br&gt;
（1）分组密码：每次处理一组元素（128bit,256bit）&lt;br&gt;
（2）流密码：连续的处理每个元素（1 字节，1 比特）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;9&#34;&gt;
&lt;li&gt;通用攻击方式（2 个）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;密码分析攻击（一个合格的密码系统应该能够阻止前两种攻击）&lt;br&gt;
（1）唯密文攻击（困难，知识少）&lt;br&gt;
（2）已知明文攻击（明文，密文固定）&lt;br&gt;
（3）选择明文攻击（明文，密文可以有条件的选择）&lt;br&gt;
（4）选择密文攻击（选择一个已知密文和明文，获得明文与密文之间的加密关系，从而破解未知密文信息）&lt;br&gt;
（5）选择文本攻击（选择明文 + 选择密文两者的结合）（简单，知识多）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/211.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C211.png&#34; alt&gt;&lt;br&gt;
（6）暴力破解（穷举攻击）&lt;br&gt;
尝试密钥集合中的每个钥匙（至少尝试可能密钥的一半）？？？&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;10&#34;&gt;
&lt;li&gt;对称加密&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;四个角色&lt;br&gt;
（1）发送方面&lt;br&gt;
（2）接收方&lt;br&gt;
（3）可信第三方密钥源（为通讯双方生成、分发密钥）&lt;br&gt;
（4）密码分析员&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;简化模型&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/212.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C212.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;完整模型&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/213.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C213.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;无条件安全&lt;br&gt;
无论计算机有多少可用的能力和时间，密码都无法被破解，因为密文提供的信息不足以唯一确定相应的明文&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;计算安全&lt;br&gt;
有限的计算机资源和时间，密码不值得被破解&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;替代（内容变化，位置、次序不变）&lt;br&gt;
明文中的字母被别的字母、数字、符号取代&lt;br&gt;
例子：凯撒加密&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/214.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C214.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;置换（内容不变，位置、次序发生改变）&lt;br&gt;
例子：栅栏技术&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/215.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C215.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第四章-分组密码和数据加密标准&#34;&gt; 第四章 分组密码和数据加密标准&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;分组密码&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;提前生成明文&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;慢&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;应用广泛&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;明文分组与密文分组大小相同（64 位或 128 位）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/216.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C216.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;流密码&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;每次生成 1byte/1bit&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;快（实时应用）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;应用窄&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;比特流生成算法（随机数生成器）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/217.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C217.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;Feistel 密码&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;实现：S-P 网络：替换 - 网络置换&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;扩散：使得密文和明文关系复杂（在大量密文上分散明文的统计结构，不利于密钥排列的推断）&lt;br&gt;
实现：置换&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;混淆：使得密文与密钥关系复杂，不利于密钥的推断&lt;br&gt;
实现：替换&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;原理&lt;br&gt;
左边明文 32/64 位经过密钥置换得到右边密文，右边明文 32/64 位经过置换得到左边密文。如此循环 16 轮&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/218.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C218.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;分组长度&lt;br&gt;
长：安全&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;迭代轮数&lt;br&gt;
多：安全&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;密钥长度&lt;br&gt;
长：安全&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;DES 加密&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;分组大小（明文）：64 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;密钥大小：64 位（但是，64 位明文，使用 56 位密钥）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;轮数：16 轮&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;密钥剩下的八位可用于奇偶校验或者随意置换&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/219.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C219.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/220.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C220.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;雪崩效应&lt;br&gt;
密钥或明文的微小改变对密文产生很大影响&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/221.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C221.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/222.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C222.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第六章-高级加密标准&#34;&gt; 第六章 高级加密标准&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;AES&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;DES 不足以阻抗暴力攻击&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;复杂结构（轮数少）VS 简单结构（轮数多）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;简单结构（分析容易，实现：硬件 or 软件）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;框架&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/223.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C223.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/224.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C224.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;具体图&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/225.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C225.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;4 个变换&lt;br&gt;
（1）字节代替：利用 S 盒&lt;br&gt;
（2）高 4 位做行值，低 4 位做列值，根据 16 进制到 S 盒中找值映射&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/226.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C226.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/227.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C227.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;行移位：简单的移位&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/228.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C228.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;列混淆&lt;br&gt;
。。。。。。？&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;轮密钥加变换&lt;br&gt;
。。。。。。？&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;AES 的密钥扩展&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;密钥扩展算法&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第七章-分组加密的工作模式&#34;&gt; 第七章 分组加密的工作模式&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;操作模式&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;目的&lt;br&gt;
（1）可以应用分组密码处理&lt;br&gt;
（2）任意大小和数据&lt;/li&gt;
&lt;li&gt;功能&lt;br&gt;
（1）加强密码应用的安全性&lt;br&gt;
（2）应用于各种不同的场景&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;分组模式&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;ECB、CBC&lt;/li&gt;
&lt;li&gt;提前准备全部的明文密文&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;流模式&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;CFB、OFB、CTR&lt;/li&gt;
&lt;li&gt;把分组密码转换成流密码&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;ECB（电码本模式）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
（1）就是使用相同的密钥对明文组进行加密，一次只加密一组明文。解密时也使用相同的密钥对密文组进行解密，一次解密一组密文。&lt;br&gt;
（2）假设明文分组长度为 b，则可以将明文分为 b 位一组的明文组，必要时，可对最后一个明文组进行填充。&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/229.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C229.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/230.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C230.png&#34; alt&gt;&lt;br&gt;
（3）在这种工作模式下，一个明文组只能固定地被加密成一个对应的密文组，一个密文组也只能固定地被解密成对应的密文组。他们彼此是一一对应的。设想我们有一个厚厚的密码本，每次加密时，我们只需要从密码本中查出明文所对应的密文就可以。这也是电码本模式名称的由来。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;优缺点&lt;br&gt;
（1）对于短消息，ECB 模式是比较适用的。但对于长消息，ECB 模式就不太安全了。这是因为长消息中会经常对相同的明文分组进行加密，得出相同的密文，这回导致频率特征暴露，造成安全隐患。&lt;br&gt;
（2）存在块重复问题&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;CBC（密文分组链连接模式）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
（1）加密算法的输入是明文分组和前一个密文分组的异或，同样均使用相同的密钥进行加密。其中第一个明文加密时，需先与初始向量 IV 异或，再进入加密算法进行加密。&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/231.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C231.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/232.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C232.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不存在块重复问题&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;优缺点分析&lt;br&gt;
（1）处理大量数据&lt;br&gt;
（2）在每次发送消息时，发送方应该把 IV 的值也秘密发送给接收方。即对于 m 个明文分组，CBC 将输出 m+1 个密文分组（ IV 也被算作密文分组的一部分）。&lt;br&gt;
（3）如果 IV 被公开，则攻击者可能会篡改 IV ，导致第一块密文解密失败。&lt;br&gt;
（4）CBC 模式存在错误传播的可能，如果前一块密文接收失败，那么会影响下一块密文的解密，但是并不会影响下下块密文的解密，最多只能影响一块，即 CBC 模式具有自同步功能。&lt;br&gt;
（5）CBC 的密文块需要按顺序逐一解密，ECB 模式可以同时解密。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;填充提示攻击？？？&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
填充提示攻击是一种利用分组密码中填充部分来进行攻击的方法。在分组密码中，当明文长度不为分组长度的整数倍时，需要在最后一个分组中填充一些数据使其凑满一个分组长度。在填充提示攻击中，攻击者会反复发送一段密文，每次发送时都对填充数据进行少许改变。由于接收者（服务器）在无法正确解密时会返回一个错误消息，攻击者通过这一错误消息就可以获得一部分与明文相关的信息。这一攻击并不仅限于 CBC 模式，而是适用所有需要进行分组填充的模式。2014 年对 SSL3.0 造成了重大影响 POODLE 攻击实际上就是一种填充示攻击。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;7&#34;&gt;
&lt;li&gt;CFB（密码反馈模式）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
（1）明文本身并没有进入加密算法中进行加密，而是与加密函数的输出进行了异或，得到了密文。CFB 以及后面要讲的 OFB、CTR 模式都具有这样的特征，这是流密码的典型特征。此外，CFB 不需要将明文分组填充到分组长度的整数倍，可以实时操作。&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/233.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C233.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/234.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C234.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;优缺点分析&lt;br&gt;
（1）密文块需要按顺序逐块加密。&lt;br&gt;
（2）密钥、明文相同时，IV 不同，则加密结果不同。&lt;br&gt;
（3）存在错误传播的可能性：前部分密文出错，会影响后边的解密。这是因为一块密文在进入下一分组的移位寄存器后，会在接下来的几个分组中一直除以移位寄存器中。&lt;br&gt;
（4）有自同步功能：在若干分组加密后，前边错误加密的密文会移出移位寄存器，停止对后面分组的加密造成影响。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;OFB（输出反馈模式）&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;第八章-伪随机数的生成和流密码&#34;&gt; 第八章 伪随机数的生成和流密码&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;随机数的 4 个典型应用&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;现在：用于阻止重放攻击在认证协议，仅使用一次随机数&lt;/li&gt;
&lt;li&gt;会话密码：用于加密消息在一个事务或一个会话中，短生存期&lt;/li&gt;
&lt;li&gt;公钥生成&lt;/li&gt;
&lt;li&gt;密钥流（流密码中）&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;三个生成器&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;TRNG（真随机数生成器）&lt;br&gt;
（1）输入：熵源（噪音…）&lt;br&gt;
（2）输出：真随机数（任意种子）&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;PRNG（伪随机数生成器）&lt;br&gt;
（1）输入：seed (种子)&lt;br&gt;
（2）输出：任意长度伪随机数&lt;br&gt;
（3）三个要求&lt;br&gt;
 1）随机性&lt;br&gt;
 a. 均匀分布性：在任何位置，是 0 或 1 的概率是 0.5&lt;br&gt;
b. 可伸缩性：对任意子序列，可以通过随机性测试&lt;br&gt;
 c. 一致性：对任意一个种子在种子集合，可生成满足要求的随机数&lt;br&gt;
 2）不可预测性&lt;br&gt;
 a. 前向不可预测性：攻击者不知道种子，知道前面的序列。攻击者不能预测下一个的输出&lt;br&gt;
 b. 后向不可预测性：攻击者知道所有的序列，不知道种子&lt;br&gt;
 3）保护种子安全。？。？？&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;PRF（伪随机函数）&lt;br&gt;
（1）输入：seed，上下文相关的结构&lt;br&gt;
（2）输出：固定长度伪随机数&lt;br&gt;
（3）确定性算法：给点一个输入，算法总是生成相同输出，无论运行多少次&lt;br&gt;
（4）非确定性算法：给定一个输入，每次运行算法，生成不同输出&lt;br&gt;
（5）危害：如果攻击中知道 seed，就会重新生成输出&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/235.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C235.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;随机数生成&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;线性同余生成器&lt;/li&gt;
&lt;li&gt;BBS 生成器&lt;/li&gt;
&lt;li&gt;硬件&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第九章-公钥密码学与-rsa&#34;&gt; 第九章 公钥密码学与 RSA&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;对称加密&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;复杂替代与置换&lt;/li&gt;
&lt;li&gt;1 个密钥&lt;/li&gt;
&lt;li&gt;问题&lt;br&gt;
（1）密钥分发，（n 个人，两两分发，一共需要 n (n-1)/2）&lt;br&gt;
（2）数字签名&lt;br&gt;
 1）报文鉴别 —— 接收者能够核实发送者对报文的签名&lt;br&gt;
 2）报文的完整性 —— 接收者不能伪造对报文的签名或更改报文内容&lt;br&gt;
 3）不可否认 —— 发送者事后不能抵赖对报文的签名&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;非对称加密&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;数学困难问题&lt;/li&gt;
&lt;li&gt;一个公钥，一个私钥&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;3 个错误认识&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;公钥密码比对称密码更安全&lt;/li&gt;
&lt;li&gt;可以放弃对称密码&lt;/li&gt;
&lt;li&gt;公钥分发是不重复的&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;公钥&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;公开，任何人可知&lt;/li&gt;
&lt;li&gt;加密&lt;/li&gt;
&lt;li&gt;验证签名算法&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;私钥&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;拥有者可知&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;解密&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;生成签名算法&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/236.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C236.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;明文：算法的输入&lt;/li&gt;
&lt;li&gt;加密算法：对明文进行各种转换&lt;/li&gt;
&lt;li&gt;公钥和私钥&lt;/li&gt;
&lt;li&gt;密文：算法输出&lt;/li&gt;
&lt;li&gt;解密算法：还原成明文&lt;/li&gt;
&lt;li&gt;6 个要求&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;易于生成公钥和私钥&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;知道公钥和明文，易于生成密文&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;知道私钥和密文，易于生成明文&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;攻击者知道公钥，不可以得出私钥&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;攻击者知道公钥和密文，不可以得到明文&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;生成签名的条件（验证，解密）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/237.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C237.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;12&#34;&gt;
&lt;li&gt;3 个典型应用&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;加密和解密（机密性）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/238.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C238.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数字签名（鉴别，安全服务）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/239.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C239.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;密钥交换&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/240.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C240.png&#34; alt&gt;&lt;br&gt;
13.RSA 和中间人攻击&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;RSA&lt;br&gt;
（1）数学困难问题：素数因子分解（n=p &lt;code&gt;*&lt;/code&gt; q (pq 互素)）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/241.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C241.png&#34; alt&gt;&lt;br&gt;
（2）pq 互素由最大公因子为 1 条件确定&lt;br&gt;
（3）定义小于 n 并且与 n 互素的数的个数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;素性测试（是否素数）&lt;br&gt;
（1）基于统计的（快）&lt;br&gt;
如果通过测试，数以一定的概率是素数&lt;br&gt;
（2）确定性的（慢）&lt;br&gt;
如果通过测试，一定是素数&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;公私钥生成&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/242.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C242.png&#34; alt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;攻击&lt;br&gt;
（1）暴力攻击&lt;br&gt;
（2）数学攻击&lt;br&gt;
（3）记时攻击&lt;br&gt;
（4）选择密文攻击&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第十章-密钥管理和其他公钥密码体制&#34;&gt; 第十章 密钥管理和其他公钥密码体制&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;D-H 密钥交换协议&lt;br&gt;
&lt;a href=&#34;https://www.jianshu.com/p/55c875969c0a&#34;&gt; https://www.jianshu.com/p/55c875969c0a&lt;/a&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
 Diffie-Hellman: 一种确保共享 KEY 安全穿越不安全网络的方法，它是 OAKLEY 的一个组成部分。Whitefield 与 Martin Hellman 在 1976 年提出了一个奇妙的密钥交换协议，称为 Diffie-Hellman 密钥交换 协议 / 算法 (Diffie-Hellman Key Exchange/Agreement Algorithm). 这个机制的巧妙在于需要安全通信的双方可以用这个方法确定 对称密钥 。然后可以用这个密钥进行 加密和解密 。但是注意，这个密钥交换协议 / 算法只能用于密钥的交换，而不能进行消息的加密和解密。双方确定要用的密钥后，要使用其他对称密钥操作加密算法实现加密和解密消息。&lt;/li&gt;
&lt;li&gt;介绍&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;DHKE 是最早的 公钥协议 之一，它允许两方安全地交换数据，因此有人嗅探双方之间的通信，交换的信息就可以泄露。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Oakley 协议是对Diffie-Hellman密钥交换算法的优化，它保留了后者的优点，同时克服了其弱点。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Diffie–Hellman (DH) 方法是 匿名密钥协商方案 ：它允许彼此没有先验知识的两方共同建立 通过不安全通道 的共享密钥。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;注意DHKE方法对嗅探攻击（数据拦截）有抵抗力，但容易受到man- 中间人攻击（攻击者秘密中继并可能 改变两方之间的通信 ）。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DH秘钥交换协议可以使用 离散对数（经典的 DHKE 算法）实现或使用 椭圆曲线加密（[ECDH]（https://en.wikipedia.org/wiki/Elliptic-curve_Diffie–Hellman）算法）。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2&gt;&lt;span id=&#34;第十一章-密码学-hash-函数&#34;&gt; 第十一章 密码学 Hash 函数&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;压缩函数&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;h=H(M)&lt;/li&gt;
&lt;li&gt;输入：任意长度的消息 M&lt;/li&gt;
&lt;li&gt;输出：固定长度的值：散列值，码，指纹，报文，摘要&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;散列函数（实现完整性，不是加密算法，不可逆）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;检测修改，不可以把修改后的消息恢复成原始消息&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;六个要求&lt;br&gt;
（1）可以处理任意长度消息 M&lt;br&gt;
（2）总是生成固定长度的值&lt;br&gt;
（3）易于计算 h=H (M)&lt;br&gt;
（4）单向性，给定 h，不可以计算出 M，正向易，反向难&lt;br&gt;
（5）抗弱碰撞性（会出现重复的值，md5 碰撞结合 php 弱比较和 md5 碰撞 SQL 漏洞&lt;br&gt;
 1）解决碰撞 https://www.cnblogs.com/hld123/p/15212563.html&lt;br&gt;
2）例子，给定 x，找出到 y，使得 H（x）=H（y）易&lt;br&gt;
（6）抗强碰撞性&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/243.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C243.png&#34; alt&gt;&lt;br&gt;
例子找出任意 x，y，使得 H（x）=H（y）难&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;3 类典型应用&lt;br&gt;
（1）消息认证&lt;br&gt;
 1）保证信息完整性&lt;br&gt;
 2）验证发送方身份&lt;br&gt;
 3）实现方法&lt;br&gt;
 a. 消息认证（3 种方法实现报文鉴别）&lt;br&gt;
消息加密（&lt;a href=&#34;https://www.cnblogs.com/block2016/p/5634808.html%EF%BC%89&#34;&gt;https://www.cnblogs.com/block2016/p/5634808.html）&lt;/a&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/244.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C244.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/245.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/12/31/learning%20share/%E4%BF%A1%E6%81%AF%E5%AE%89%E5%85%A8%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0/D:%5Cblog%5Cmyblog%5Csource%5Cimage%5C245.png&#34; alt&gt;&lt;br&gt;
消息鉴别码 MAC&lt;br&gt;
 散列函数&lt;br&gt;
 b. 数字签名&lt;br&gt;
 c. 其余应用&lt;br&gt;
产生单向口令文件&lt;br&gt;
入侵检测和病毒检测&lt;br&gt;
构建随机函数，伪随机数发生器&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第十二章-消息认证码&#34;&gt; 第十二章 消息认证码&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;消息认证函数（MAC）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;MAC=（K，M）&lt;/li&gt;
&lt;li&gt;M：任意长度的消息&lt;/li&gt;
&lt;li&gt;K：私钥&lt;/li&gt;
&lt;li&gt;不是加密算法（不可逆）&lt;/li&gt;
&lt;li&gt;MAC：固定长度的值，鉴别符&lt;br&gt;
（1）理论上：多对一函数，存在多个消息相同的 MAC 值&lt;br&gt;
（2）实际上：找到多个消息有相同 MAC 值不可能&lt;/li&gt;
&lt;li&gt;3 个要求（假设攻击者不知道 K）&lt;br&gt;
（1）攻击者知道 M，生成一个新消息 N，满足 C（K，N）=C（K，M）&lt;br&gt;
（2）C（K，M）均匀分布，概率都为 2 的 - n 次方&lt;br&gt;
（3）不存在弱碰撞（weak spot）&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第十三章-数字签名&#34;&gt; 第十三章 数字签名&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;数字签名&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;报文鉴别：接收者能够核实发送者对报文的签名，其他人无法伪造此签名；&lt;/li&gt;
&lt;li&gt;报文的完整性：接收者确信所收的数据和发送者发送的完全一样；&lt;/li&gt;
&lt;li&gt;不可否认：发送者事后不能抵赖对报文的签名。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第十四章-密钥管理和分发&#34;&gt; 第十四章 密钥管理和分发&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;密钥的分发和管理&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;问题&lt;br&gt;
（1）密钥的分发&lt;br&gt;
（2）存储和管理大量的密钥&lt;br&gt;
（3）私钥加密体系在开放系统中的不适用性&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;第十五章-用户认证&#34;&gt; 第十五章 用户认证&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;用户认证&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;用户认证原理&lt;br&gt;
（1）鉴定阶段&lt;br&gt;
给安全系统提供身份标识（QQ 号，IP 地址）&lt;br&gt;
（2）核实阶段&lt;br&gt;
提供认证信息（密码）&lt;/li&gt;
&lt;li&gt;认证方式&lt;br&gt;
（1）知道什么&lt;br&gt;
口令，个人身份号（PIN），电话号码&lt;br&gt;
（2）拥有什么&lt;br&gt;
加密密钥，电子密钥卡，智能卡，统称为令牌&lt;br&gt;
（3）特征（静态生物特征，动态生物特征）&lt;br&gt;
指纹，视网膜，脸，声音，手写特征，打字节奏&lt;/li&gt;
&lt;li&gt;单项认证&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;什么是-qt&#34;&gt; 什么是 qt&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;Qt（官方发音 [kju:t]，音同 cute）是一个跨平台的 C++ 开发库，主要用来开发图形用户界面（Graphical User Interface，GUI）程序，当然也可以开发不带界面的命令行（Command User Interface，CUI）程序。&lt;/li&gt;
&lt;li&gt;Qt 是纯 C++ 开发的，所以学好 C++ 非常有必要&lt;/li&gt;
&lt;li&gt;Qt 还存在 Python、Ruby、Perl 等脚本语言的绑定， 也就是说可以使用脚本语言开发基于 Qt 的程序。&lt;/li&gt;
&lt;li&gt;Qt 支持的操作系统有很多，例如通用操作系统 Windows、Linux、Unix，智能手机系统 Android、iOS、WinPhone， 嵌入式系统 QNX、VxWorks 等等&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;qt-发展史&#34;&gt; qt 发展史&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;Qt 由奇趣科技公司（Trolltech）的两位创始人于 1990 年着手开发，1995 年发布 Qt  1.0。&lt;/li&gt;
&lt;li&gt;2008 年，奇趣科技被诺基亚公司收购，Qt 也因此成为诺基亚旗下的编程语言工具。&lt;/li&gt;
&lt;li&gt;在智能手机的冲击下诺基亚大厦轰然倒塌，2012 年将 Qt 转让给 Digia 公司。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;qt-应用程序框架英文路径&#34;&gt; qt 应用程序框架（&lt;strong&gt;英文路径！！！&lt;/strong&gt;)&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;项目-application&#34;&gt; 项目 (Application)&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Qt Widgets Application，支持桌面平台的有图形用户界面（Graphic User Interface，GUI） 界面的应用程序。GUI 的设计完全基于 C++ 语言，采用 Qt 提供的一套 C++ 类库。&lt;/li&gt;
&lt;li&gt;Qt Console Application，控制台应用程序，无 GUI 界面，一般用于学习 C/C++ 语言，只需要简单的输入输出操作时可创建此类项目。&lt;/li&gt;
&lt;li&gt;Qt Quick Application，创建可部署的 Qt Quick 2 应用程序。Qt Quick 是 Qt 支持的一套 GUI 开发架构，其界面设计采用 QML 语言，程序架构采用 C++ 语言。利用 Qt Quick 可以设计非常炫的用户界面，一般用于移动设备或嵌入式设备上无边框的应用程序的设计。&lt;/li&gt;
&lt;li&gt;Qt Quick Controls 2 Application，创建基于 Qt Quick Controls 2 组件的可部署的 Qt Quick 2 应用程序。Qt Quick Controls 2 组件只有 Qt 5.7 及以后版本才有。&lt;/li&gt;
&lt;li&gt;Qt Canvas 3D Application，创建 Qt Canvas 3D QML 项目，也是基于 QML 语言的界面设计，支持 3D 画布。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;类信息-details&#34;&gt; 类信息 (Details)&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;基类 (父类)&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;QMainWindow 是主窗口类，主窗口具有主菜单栏、工具栏和状态栏，类似于一般的应用程序的主窗口&lt;/li&gt;
&lt;li&gt;QWidget 是所有具有可视界面类的基类，选择 QWidget 创建的界面对各种界面组件都可以 支持&lt;/li&gt;
&lt;li&gt;QDialog 是对话框类，可建立一个基于对话框的界面&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;编译运行&#34;&gt; 编译运行&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C6.png&#34; alt&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;qapplication-应用程序类&#34;&gt; QApplication 应用程序类&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;QT 头文件没有.h，头文件和类名一样&lt;/li&gt;
&lt;li&gt;有且只有一个应用程序类的对象&lt;br&gt;
 QApplication (argc,argv)&lt;/li&gt;
&lt;li&gt;QWidget 是一个窗口基类，所有继承它的类也可以理解为窗口类，窗口创建好后默认隐藏，显示出来需要人为调用 show () 函数&lt;/li&gt;
&lt;li&gt;a.exec ()；让程序一直执行 (while), 等待用户操作&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;pro-项目&#34;&gt; pro 项目&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;注释： #&lt;/li&gt;
&lt;li&gt;模块？？？&lt;/li&gt;
&lt;li&gt;高于 qt4 版本，为了兼容 qt4&lt;br&gt;
greaterThan(QT_MAJOR_VERSION, 4): QT += widgets&lt;/li&gt;
&lt;li&gt;应用程序的名字&lt;br&gt;
 TARGET = 01_test&lt;/li&gt;
&lt;li&gt;指定 makefile 的类型&lt;br&gt;
 TEMPLATE = app&lt;/li&gt;
&lt;li&gt;源文件 .cpp&lt;br&gt;
SOURCES += main.cpp&lt;br&gt;
widget.cpp&lt;/li&gt;
&lt;li&gt;头文件 .h&lt;br&gt;
HEADERS  += widget.h&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;模块&#34;&gt; 模块&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C7.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C8.png&#34; alt&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;指定父对象&#34;&gt; 指定父对象&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;比如我要在窗口中显示一个按钮&lt;br&gt;
如果不指定父对象，对象和对象之间没有关系，独立显示&lt;br&gt;
所以要指定对象&lt;br&gt;
如果 a 指定 b 为它的父对象，a 就在 b 上面&lt;br&gt;
指定父对象：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;setParent&lt;br&gt;
eg:  b.settParent(&amp;amp;a)&lt;/li&gt;
&lt;li&gt;通过构造函数传参&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;信号和槽&#34;&gt; 信号和槽&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;信号和槽是 Qt 特有的消息传输机制，它能将相互独立的控件关联起来。&lt;br&gt;
在 Qt 中，用户和控件的每次交互过程称为一个事件&lt;br&gt;
 Qt 中的所有控件都具有接收信号的能力，一个控件还可以接收多个不同的信号&lt;br&gt;
在 Qt 中，对信号做出的响应动作就称为槽&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C9.png&#34; alt&gt;&lt;br&gt;
QPushButton b1;&lt;br&gt;
 想要 b1 具有点击或者其他效果&lt;br&gt;
 connext (&amp;amp;b1,&amp;amp;QPushButton::pressed,this,&amp;amp;MainWidget::close)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&amp;amp;b1：信号发出者，指针类型&lt;/li&gt;
&lt;li&gt;&amp;amp;QPushButton::pressed：处理的信号，	&amp;amp; 发送者的名字：：信号名字&lt;/li&gt;
&lt;li&gt;this：信号接收者&lt;/li&gt;
&lt;li&gt;&amp;amp;MainWidget::close：槽函数，信号处理函数	&amp;amp; 接收的类名：：槽函数名字&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;自定义槽&#34;&gt; 自定义槽&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;自定义槽：普通函数的用法&lt;br&gt;
 Qt5: 任意的成员函数，普通全局函数，静态函数&lt;br&gt;
槽函数需要和信号__一致__（参数，返回值）&lt;br&gt;
由于信号都是没有返回值，所以槽函数一定没有返回值&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;自定义信号&#34;&gt; 自定义信号&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;信号必须有 signals 关键字来声明&lt;br&gt;
信号没有返回值，但可以有参数&lt;br&gt;
信号就是函数的声明，只需声明，无需定义&lt;br&gt;
使用：emit mySignal ();&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;坐标系统&#34;&gt; 坐标系统&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;对于父窗口 (子窗口)，坐标系统相对于屏幕&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;原点：相对于屏幕左上角&lt;/li&gt;
&lt;li&gt;x：往右递增&lt;/li&gt;
&lt;li&gt;y：往下递增&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;常见的通信方式&#34;&gt; 常见的通信方式&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;管道 pipe：管道是一种半双工的通信方式，数据只能单向流动，而且只能在具有亲缘关系的进程间使用。进程的亲缘关系通常是指父子进程关系。&lt;/li&gt;
&lt;li&gt;命名管道 FIFO：有名管道也是半双工的通信方式，但是它允许无亲缘关系进程间的通信。&lt;/li&gt;
&lt;li&gt;消息队列 MessageQueue：消息队列是由消息的链表，存放在内核中并由消息队列标识符标识。消息队列克服了信号传递信息少、管道只能承载无格式字节流以及缓冲区大小受限等缺点。&lt;/li&gt;
&lt;li&gt;共享存储 SharedMemory：共享内存就是映射一段能被其他进程所访问的内存，这段共享内存由一个进程创建，但多个进程都可以访问。共享内存是最快的 IPC 方式，它是针对其他进程间通信方式运行效率低而专门设计的。它往往与其他通信机制，如信号两，配合使用，来实现进程间的同步和通信。&lt;/li&gt;
&lt;li&gt;信号量 Semaphore：信号量是一个计数器，可以用来控制多个进程对共享资源的访问。它常作为一种锁机制，防止某进程正在访问共享资源时，其他进程也访问该资源。因此，主要作为进程间以及同一进程内不同线程之间的同步手段。&lt;/li&gt;
&lt;li&gt;套接字 Socket：套解口也是一种进程间通信机制，与其他通信机制不同的是，它可用于不同及其间的进程通信。&lt;/li&gt;
&lt;li&gt;信号 (sinal) ： 信号是一种比较复杂的通信方式，用于通知接收进程某个事件已经发生。&lt;/li&gt;
&lt;/ol&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;管道&#34;&gt; 管道&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;管道是操作系统中常见的一种进程间通信方式，它使用于所有 POSIX 系统以及 Windows 系列产品。&lt;/p&gt;
&lt;p&gt;管道也是 unix ipc 的最老形式，管道有两种限制：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;数据自己读不能自己写&lt;/li&gt;
&lt;li&gt;它们是半双工的。数据只能在一个方向上流动。&lt;/li&gt;
&lt;li&gt;数据一旦被读走，便不在管道中存在，不可反复读取。&lt;/li&gt;
&lt;li&gt;它们只能在具有公共祖先的进程之间使用。通常，一个管道由一个进程创建，然后该进程调用 fork, 此后父、子进程之间就可应用该管道。&lt;/li&gt;
&lt;/ol&gt;

 &lt;h2&gt;&lt;span id=&#34;const-修饰符&#34;&gt; const 修饰符&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;1.const 作用与 #define 相似，但是它消除了 #define 的不安全性比如：&lt;br&gt;
#define T1 a+a&lt;br&gt;
#define T2 T1-T1&lt;br&gt;
2.const 与指针组合可以归纳为 3 种类型；&lt;br&gt;
(1) 指向常量的指针&lt;br&gt;
 3. 指向常量的指针&lt;br&gt;
 const char * name=“chen”;&lt;br&gt;
name=“zhang”;&lt;br&gt;
4. 常指针&lt;br&gt;
 char * const name=“chen”;&lt;br&gt;
name[3]=‘a’;&lt;br&gt;
5. 指向常量的常指针&lt;br&gt;
 const char * const name=“chen”;&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;内联函数&#34;&gt; 内联函数&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;原因：为了消除函数调用时的系统开销，以提高运行速度。&lt;br&gt;
inline int box(int i,int j,int k)&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int a,b,c,v;&lt;br&gt;
cin&amp;gt;&amp;gt;a&amp;gt;&amp;gt;b&amp;gt;&amp;gt;c;&lt;br&gt;
v=box(a,b,c);&lt;br&gt;
cout&amp;lt;&amp;lt;“a * b * c=”&amp;lt;&amp;lt;v&amp;lt;&amp;lt;endl;&lt;br&gt;
return 0;&lt;br&gt;
}&lt;br&gt;
inline int box(int i,int j,int k)&lt;br&gt;
{&lt;br&gt;
return i * j * k;&lt;br&gt;
}&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;带有默认参数的函数&#34;&gt; 带有默认参数的函数&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;要求：在声明函数时，所有带有默认值的参数必须出现在不指定默认值参数的右边。&lt;br&gt;
错误：int fun (int i,int j=5,int k);&lt;br&gt;
 正确：int fun (int i,int k,int j=5);&lt;/li&gt;
&lt;li&gt;要求：函数调用时，如果某一个参数省略，后面的参数只能省略采取默认值，不能赋予新的值。&lt;br&gt;
错误：special (,21.5);&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;函数的重载&#34;&gt; 函数的重载&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;含义：当两个或两个以上的函数共有一个函数名时，称为函数的重载。&lt;br&gt;
例如：&lt;br&gt;
int square(int i)&lt;br&gt;
{&lt;br&gt;
return i * i;&lt;br&gt;
}&lt;br&gt;
long square(long l)&lt;br&gt;
{&lt;br&gt;
return l * l;&lt;br&gt;
}&lt;br&gt;
double square(double d)&lt;br&gt;
{&lt;br&gt;
return d * d;&lt;br&gt;
}&lt;/li&gt;
&lt;li&gt;注意：调用重载函数时，如果两个函数的参数和类型都相同，而只有返回值类型不同，则不允许重载。&lt;br&gt;
例如：&lt;br&gt;
int mul(int x,int y);&lt;br&gt;
double mul(int x,int y);&lt;br&gt;
 不允许重载&lt;/li&gt;
&lt;li&gt;注意：函数的重载与带默认值的函数一起使用时，有可能引起二义性&lt;br&gt;
比如：&lt;br&gt;
void Drawcircle(int r=0,int x=0,int y=0);&lt;br&gt;
void Drawcircle(int r);&lt;br&gt;
 当执行 Drawcircle (20);&lt;br&gt;
 系统无法确定调用哪一个函数&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;作用域运算符-quotquot&#34;&gt; 作用域运算符 &amp;quot;::&amp;quot;&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;通常情况下，局部变量在作用域内具有较高的优先权，它将屏蔽全局变量。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果希望在局部变量的作用域内使用同名的全局变量，可以在这个变量前加上 &amp;quot;::&amp;quot;,&amp;quot;::&amp;quot; 称为：作用域运算符&lt;br&gt;
例如：&lt;br&gt;
int avar;&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int avar;&lt;br&gt;
avar=25;   // 给局部变量赋值 25&lt;br&gt;
::avar=10;  // 给全局变量赋值&lt;br&gt;
 cout&amp;lt;&amp;lt;“local avar=”&amp;lt;&amp;lt;avar&amp;lt;&amp;lt;endl;&lt;br&gt;
cout&amp;lt;&amp;lt;“global avar =”&amp;lt;&amp;lt;::avar&amp;lt;&amp;lt;endl;&lt;br&gt;
return 0;&lt;br&gt;
}&lt;br&gt;
 输出：&lt;br&gt;
local avar =25&lt;br&gt;
global avar =10&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;运算符-new-和-delete&#34;&gt; 运算符 new 和 delete&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;new&lt;br&gt;
int * p;&lt;br&gt;
p=new int;&lt;/li&gt;
&lt;li&gt;delete&lt;br&gt;
delete p;&lt;/li&gt;
&lt;li&gt;注意：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;使用 new 为多维数组分配空间时，必须提供所有维的大小&lt;br&gt;
如：int * pi =new int [2][3][4];&lt;/li&gt;
&lt;li&gt;new 可在为简单变量分配内存的同时，进行初始化。&lt;br&gt;
指针变量名 = new 类型（初值）&lt;br&gt;
int * p;&lt;br&gt;
p=new int(99);&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;引用&#34;&gt; 引用&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;别名&lt;br&gt;
 int i=5;&lt;br&gt;
int &amp;amp;j=i;&lt;br&gt;
 注意：i 和 j 的地址一样，i 和 j 同时变化。&lt;br&gt;
不能建立 void 类型&lt;br&gt;
不能建立引用的数组&lt;br&gt;
不能建立引用的引用&lt;/li&gt;
&lt;li&gt;引用作为函数参数&lt;br&gt;
例如：&lt;br&gt;
void swap(int &amp;amp;m,int &amp;amp;n)&lt;br&gt;
{&lt;br&gt;
int temp;&lt;br&gt;
temp=m;&lt;br&gt;
m=n;&lt;br&gt;
n=temp;&lt;br&gt;
}&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int a=5,b=10;&lt;br&gt;
swap(a,b);&lt;br&gt;
}&lt;/li&gt;
&lt;li&gt;使用引用返回函数值&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;结构体与类&#34;&gt; 结构体与类&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;类是对象的抽象，对象是类的实例。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;注意：私有成员 (数据成员和成员函数) 只能被类内的成员函数访问，不能被类外的对象访；公有成员都可以被访问&lt;/li&gt;
&lt;li&gt;注意：在实际应用中，一般把需要保护的数据设置为私有的，把它隐蔽起来，把成员函数设置为公有的，作为类与外界的接口。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;成员函数的定义&#34;&gt; 成员函数的定义&lt;/span&gt;&lt;/h2&gt;
&lt;h2&gt;&lt;span id=&#34;静态成员&#34;&gt; 静态成员&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;静态数据成员&lt;br&gt;
 1. 当我们想要用在__同一个类中 (学生类)&lt;strong&gt; 任何一个对象__共享__一个数据 (这个数据可以累计前面对象的数据情况，不会随着定义下一个对象就刷新)(&lt;strong&gt;平均分、学生总人数、总成绩…&lt;/strong&gt;)，就应该将这个数据定义为静态数据成员&lt;br&gt;
 2. 虽然将数据成员定义为全局变量也可以达到同样的目的，但是全局变量具有__不安全性&lt;/strong&gt;，&lt;strong&gt;破坏面对象程序的封装性__特点&lt;br&gt;
 3.&lt;strong&gt; 格式：&lt;/strong&gt;&lt;br&gt;
static 数据成员 数据成员名&lt;br&gt;
 4. 静态数据成员初始化应该在类外单独进行，而且在定义对象之前进行&lt;br&gt;
 5.&lt;strong&gt; 初始化格式：&lt;/strong&gt;&lt;br&gt;
数据类型 类名：：静态数据成员名 = 初始值&lt;br&gt;
注意：数据成员名之前不要加 static&lt;br&gt;
6.&lt;strong&gt; 静态数据成员属于类&lt;/strong&gt;，而__普通数据成员属于对象&lt;/strong&gt;，因此在访问静态数据成员时，__可以 (并非只能)__用类名访问，格式：&lt;br&gt;
类名：：静态数据成员名&lt;br&gt;
 7. 用对象访问静态数据成员格式：&lt;br&gt;
对象名。静态数据成员名&lt;br&gt;
 8. 私有静态数据成员不能在类外被访问，应该通过公有成员函数访问&lt;/li&gt;
&lt;li&gt;静态数据成员函数&lt;br&gt;
 1. 静态成员函数属于整个类，是该类所有对象共享的成员函数&lt;br&gt;
 2.&lt;strong&gt; 格式：&lt;/strong&gt;&lt;br&gt;
static 返回类型 静态成员函数名 (参数表)；&lt;br&gt;
3.&lt;strong&gt; 调用格式:&lt;/strong&gt;&lt;br&gt;
(规范) 类名：：静态成员函数名 (实参表)&lt;br&gt;
 4. 使用静态成员函数其中一个原因是，可以用它在建立任何对象之前调用静态成员函数，以处理静态数据成员。原因：&lt;strong&gt;在调用静态成员函数中的静态成员已经被初始化&lt;/strong&gt;，可以用来调用以及运算&lt;br&gt;
 5. 编译系统将静态成员函数限定为内部连接，所以其他文件中的同名函数不会与该函数发生冲突&lt;br&gt;
 6. 静态成员函数与非静态成员函数的区别为：&lt;strong&gt;非静态成员函数有 this 指针，而静态成员函数没有&lt;/strong&gt;&lt;br&gt;
 7. 一般来说__静态成员函数不能访问类中的非静态成员__，若要访问只能通过 (对象名、&lt;strong&gt;对象指针、对象引用&lt;/strong&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;友元&#34;&gt; 友元&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;友元函数&lt;br&gt;
 1. 类中的私有成员是受保护的，只有类中的成员函数能访问 (一般调用构造函数), 此时友元函数便可以作为一个小口子用来访问其中的私有成员&lt;br&gt;
 2. 既可以是不属于类的非成员函数 (普通函数)，也可以是另一个类的成员函数&lt;br&gt;
 3. 友元函数可以定义在类的内部，也可以定义在类的外部&lt;br&gt;
 4. 定义友元函数需要在函数名之前加上关键字 friend&lt;br&gt;
5. 由于友元函数权限范围很大，不可具体划分为某一类成员函数，属于一种特殊的函数，因此在外部定义时，&lt;strong&gt;按照普通函数的定义即可&lt;/strong&gt;&lt;br&gt;
 6. 友元函数时特殊的函数，&lt;strong&gt;不属于类的成员&lt;/strong&gt;，所以它不能直接访问对象的数据成员，也不可以通过 this 指针访问，&lt;strong&gt;必须通过 (对象指针或者对象的引用) 来实现&lt;/strong&gt;&lt;br&gt;
 7.&lt;strong&gt; 使用友元函数可以提高运行效率&lt;/strong&gt;&lt;br&gt;
类中的私有成员不可以被类外部访问，必须构造函数进行调用，这时候，如果大量需要访问私有成员，就会不停的调用函数进行访问，浪费时间，降低运行效率&lt;/li&gt;
&lt;li&gt;将成员函数声明为友元函数&lt;br&gt;
 1. 当有两个类时，我想要__两个类中的数据有共同使用的部分__(&lt;strong&gt;在一个类中调用另一个类中的私有数据成员&lt;/strong&gt;)，&lt;strong&gt;就可以在其中一个类 A 中将函数声明为它的成员函数，在另一个类 B 中声明为 A 中的成员函数为 B 的友元函数，其中 A 中的私有数据成员可以直接 cout,B 中要访问私有数据成员就要用 (对象指针或者对象的引用) 来调用私有数据成员来 cout&lt;/strong&gt;&lt;br&gt;
2. 注意类的引用声明以及定义&lt;/li&gt;
&lt;li&gt;友元类&lt;br&gt;
 1. 格式：&lt;br&gt;
friend 类名；&lt;br&gt;
2. 当类 Y 被说明为类 X 的友元时，类 Y 中的所有成员函数都可以访问 X 中的__所有__数据成员&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;类的组合&#34;&gt; 类的组合&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;class X&lt;br&gt;
{&lt;br&gt;
类名 1  对象成员 1；&lt;br&gt;
类名 2  对象成员 2；&lt;br&gt;
.&lt;br&gt;
.&lt;br&gt;
.&lt;br&gt;
 类名 n  对象成员 n;&lt;br&gt;
}；&lt;br&gt;
类 X 的构造函数定义为：&lt;br&gt;
X::X (形参表 0）：对象成员 1（形参表 1），对象成员 2（形参表 2），…&lt;br&gt;
{&lt;br&gt;
// 类 X 的函数构造体&lt;br&gt;
}&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;常类型&#34;&gt; 常类型&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;常类型是指使用类型修饰符 const 说明的类型，常类型的变量或者对象成员的值在程序运行期间是不可以改变的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;常引用&lt;br&gt;
例如：&lt;br&gt;
int a=5;&lt;br&gt;
const int &amp;amp;b=a;&lt;br&gt;
b 是一个常引用，这时候 b 的 值可以随 a 的值而改变 (可以改变 a 的值)，而不可以改变 b 的值&lt;/li&gt;
&lt;li&gt;常对象&lt;br&gt;
常对象的数据成员值在整个生存期内不能被改变&lt;br&gt;
格式：&lt;br&gt;
类名 const 对象名 [(参数表)]；&lt;br&gt;
或者&lt;br&gt;
 const 类名 对象名 [(参数表)]；&lt;br&gt;
&lt;strong&gt;常对象不能调用普通成员函数&lt;/strong&gt;&lt;br&gt;
&lt;strong&gt;在定义对象时必须进行初始化，而且不能被更新&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;常对象成员&lt;br&gt;
 1. 常数据成员&lt;br&gt;
使用 const 说明的数据成员称为常数据成员，如果一个类中说明了常数据成员，那么构造函数就只能通过成员初始化列表对该数据成员进行初始化，并且其他任何函数都不能对该成员赋值&lt;/li&gt;
&lt;li&gt;常成员函数&lt;br&gt;
在类中使用关键字 const 说明的成员函数为常成员函数&lt;br&gt;
格式：&lt;br&gt;
类型说明符  函数名 (参数表) const；&lt;br&gt;
常成员函数可以访问常数据成员，也可以访问普通数据成员。常数据成员可以被常成员函数访问也可以被普通成员函数访问&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;派生类的概念&#34;&gt; 派生类的概念&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;当两个类有很多相同的地方，为了提高代码的可重用性，可以引入继承&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;派生类的声明&lt;br&gt;
 class 派生类名：[继承方式] 基类名&lt;br&gt;
 {派生类新增的数据成员和成员函数}；&lt;br&gt;
继承方式可以为：private (私有继承)、protected (保护继承)、public (公有继承)&lt;br&gt;
 如果没有给出继承方式，系统默认为私有继承&lt;/li&gt;
&lt;li&gt;派生类的构成&lt;br&gt;
派生类把基类的全部成员 (除构造函数和析构函数之外) 接收过来&lt;/li&gt;
&lt;li&gt;基类成员在派生类中的访问属性&lt;br&gt;
 1. 基类中的私有成员&lt;br&gt;
无论哪种继承方式，基类中的私有成员不允许派生类继承&lt;br&gt;
 2. 基类中的公有成员&lt;br&gt;
当类中的成员以什么方式继承时，基类中的所有公有成员就以什么成员的方式出现&lt;br&gt;
 3. 基类中的保护成员&lt;br&gt;
当类中的成员以公有或保护方式继承时，基类中的所有保护成员就以保护成员的方式出现&lt;br&gt;
当类中的成员为私有继承时，基类中的所有保护成员就以私有成员的方式继承&lt;/li&gt;
&lt;li&gt;派生类对基类成员的访问属性&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;在公有派生类&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;在私有派生类&lt;/th&gt;
&lt;th&gt;在保护派生类&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;私有成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可直接访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不可直接访问&lt;/td&gt;
&lt;td&gt;不可直接访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;公有成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;公有&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;私有&lt;/td&gt;
&lt;td&gt;保护&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;保护成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;保护&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;私有&lt;/td&gt;
&lt;td&gt;保护&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;派生类对基类成员的访问规则&lt;br&gt;
类的继承方式有 public (公有继承)、protected (保护继承)、private (私有继承)&lt;br&gt;
 访问形式：内部访问、对象访问&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;私有继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
&lt;th&gt;保护成员&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;对象访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不可访问&lt;/td&gt;
&lt;td&gt;不可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;公有继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
&lt;th&gt;保护成员&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;对象访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;不可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;保护继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
