&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
